import React from 'react';
import Navbar from './components/Navbar';
import Sidebar from './components/Sidebar';
import Statscard from './components/Statscard';
import PatientTable from './components/PatientTable';
import './App.css';

function App() {
  return (
    <div className="app-shell">
      {/* 1. Header is global at the top */}
      <Navbar />

      <div className="main-wrapper">
        {/* 2. Sidebar stays fixed on the left */}
        <Sidebar />

        {/* 3. Content Area for the Dashboard */}
        <main className="content-area">
          <div className="dashboard-header">
            <h1>Hospital Overview</h1>
            <p>Welcome back, Administrator</p>
          </div>

          {/* 4. The Stat Cards Grid */}
          <div className="stats-grid">
            <Statscard title="Total Patients" value="1,240" icon="👥" color="#3498db" trend="+12%" />
            <Statscard title="Available Beds" value="42" icon="🛏️" color="#e67e22" trend="85% full" />
            <Statscard title="Appointments" value="18" icon="📅" color="#9b59b6" trend="4 Pending" />
            <Statscard title="Total Revenue" value="$12,450" icon="💰" color="#2ecc71" trend="+5%" />
          </div>


          {/* This is where the Table or Charts will go later */}
          <div className="placeholder-section">
            <p>Main Charts and Patient Tables will load here...</p>
          </div>


        </main>
      </div>
    </div>
  );
}

export default App;
